insert into public.sop_documents
  (id, title, category, content, status, order_num, script, quizzes, doc_type, parent_id, company_id, created_at, updated_at)
values
  ('sop-slko-slime-picnic', '슬라임 피크닉 교육매뉴얼', '운영 매뉴얼',
   '롯데 스타필드마켓 죽전 1층 슬라라 슬라임 피크닉 팝업의 운영 교육이에요. 슬라이드 17장을 따라가며 가격·체험 진행·운영·안전·연락처까지 차근차근 익혀 보세요.',
   'published', 1,
   '[{"scene": 1, "visual": "인트로", "narration": "안녕하세요! 우리 매장은 롯데 스타필드마켓 죽전 1층에 있는 슬라라 슬라임 피크닉 팝업이에요. 가족과 아이들이 즐겁게 놀다 가는 곳이죠. 오늘은 이곳에서 손님을 어떻게 맞이하고 체험을 진행하는지 하나씩 배워볼게요. 준비됐나요? 그럼 시작할게요!", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide01.jpg", "type": "infographic"}, {"scene": 2, "visual": "체험 한눈에", "narration": "먼저 우리 체험을 한눈에 살펴볼게요. 기본 요금은 한 분에 1만 8천 원, 이용 시간은 한 시간이에요. 체험 게임은 세 종류로, 아이스크림 슬라임과 뮤지컬 연계 테마가 있고, 게임 두 종류에 자유 체험 두 종류로 운영해요. 여기에 인스타그램 게시물과 팔로우 이벤트로 리워드도 드리는, 작지만 알찬 프리미엄 콘텐츠랍니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide02.jpg", "type": "infographic"}, {"scene": 3, "visual": "행사 목표 · 첫인사", "narration": "우리가 가장 중요하게 생각하는 가치는 ‘재미, 친절, 그리고 플러스원’이에요. 아이들이 웃으면서 즐겁게 놀다 갈 수 있도록, 행사 기간 내내 한 번이라도 더 아이들과 눈을 맞추고 말을 걸어 주세요. 이번 행사의 큰 목표는 두 가지예요. 하나는 영종도 인스파이어에 있는 슬라라 매장을 알리는 거예요. 인스타그램 ‘슬라라 월드’ 계정을 안내해 주시고요. 다른 하나는 매출을 올리는 거예요. 그 시작은 언제나 밝은 인사랍니다. ‘안녕하세요, 슬라라입니다!’ 행사 기간은 5월 29일부터 6월 10일까지, 철수는 6월 11일 오후 2시부터예요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide03.jpg", "type": "infographic"}, {"scene": 4, "visual": "패키지 · 가격 · 연령", "narration": "기본 패키지는 한 분에 1만 8천 원이에요. 슬라임 빙수 만들기와 아이스크림 슬라임에, 파츠와 스탬프 팜플렛, 구디백, 스티커까지 모두 포함돼요. 그리고 기본 게임 두 종류 중에 하나를 골라서 진행해 드려요. 권장 연령은 만 세 살부터고, 여덟 살 이하 어린이는 꼭 보호자와 함께 입장해 주세요. 정원은 어린이 70명 기준이고, 예약 없이 현장에서 결제하시면 돼요. 혹시 게임을 하나 더 하고 싶어 하시면 3천 원만 추가하면 되는데, 추가 게임을 하신 분께는 파츠를 담을 수 있는 컵을 하나 더 드려요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide04.jpg", "type": "infographic"}, {"scene": 5, "visual": "체험 흐름 · 진행 멘트", "narration": "이제 체험이 어떤 순서로 흘러가는지 볼게요. 먼저 현장에서 결제를 하고, 슬라임 빙수를 만든 다음, 플레잉존에서 한 시간 동안 체험을 즐겨요. 미니게임 세 가지 중에 하나를 고르고, 마지막엔 리워드로 받은 슬라임을 슬라임 월에 붙이고 사진도 찍는답니다. 체험 종류로는 눈꽃 슬라임, 대형 바닥풍선, 얼음 낚시가 있어요. 바닥풍선을 진행할 땐 이렇게 말해 주세요. 먼저 ‘안녕하세요, 슬라라 바풍존입니다!’ 하고 반갑게 인사하고요. ‘먼저 연습 한 번 해 볼게요’, 그다음 ‘이제 본 게임 시작할게요! 준비되시면 시작해 주세요!’ 끝나면 ‘체험 완료됐습니다!’ 하고 밝게 마무리해 주시면 돼요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide05.jpg", "type": "infographic"}, {"scene": 6, "visual": "슬라임 카페 · 추가구매 · 응대", "narration": "아이스크림 슬라임 체험은 ‘슬라임 카페’라고도 불러요. 마찬가지로 한 분에 1만 8천 원이고, 만들기 키트와 파츠, 스탬프 팜플렛, 구디백, 스티커가 들어가요. 손님이 오시면 카운터에서 스티커 뒷면에 체험이 끝나는 시간을 적어 주세요. 예를 들어 1시에 오셨으면 2시라고 적고, 한 시간 이용이라고 안내해 드리면 돼요. 추가 구매도 안내해 주세요. 아이스크림은 1만 2천 원, 파츠 한 통은 3천 원, 토핑은 2천 원이에요. 스티커는 구디백을 예쁘게 꾸미는 용도라고 알려 주시고요. 머리가 긴 친구에게는 머리끈을 하나씩 챙겨 주는 센스도 잊지 마세요! 혹시 ‘여기 뭐 하는 곳이에요?’ 하고 물으시면, ‘슬라임 카페예요. 1만 8천 원에 앉아서 만드실 수 있는 키트를 다 드리고, 옆에 있는 두 게임 중 하나도 체험하실 수 있어요!’라고 밝게 안내해 주세요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide06.jpg", "type": "infographic"}, {"scene": 7, "visual": "체험존 현장", "narration": "이건 실제 체험존의 모습이에요. 아이들이 어떻게 즐기는지 눈으로 한번 익혀 두시면, 손님을 안내할 때 훨씬 자연스러워요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide07.jpg", "type": "infographic"}, {"scene": 8, "visual": "오픈 · 마감", "narration": "매장 문을 열고 닫을 때 해야 할 일이에요. 오픈 전에는 바닥 청소를 깨끗이 해 주세요. 문을 연 뒤에는 체험존과 굿즈존 사진을 찍어서 단체 채팅방에 공유하고요. 하역장에 나오는 쓰레기는 그날그날 바로 처리해 주세요. 마무리하면 본부장님께 개인 메시지로 보고해 주시면 됩니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide08.jpg", "type": "infographic"}, {"scene": 9, "visual": "슬라임 월 포토존", "narration": "슬라임 월은 아이들이 직접 만든 슬라임으로 벽을 꾸미는 포토존이에요. ‘내가 만든 빙수 슬라임으로 슬라임 월을 꾸며 보자!’ 하고 권해 주세요. 직접 만든 아이스크림 슬라임이나, 인스타그램 이벤트 리워드로 받은 슬라임을 벽에 붙이고 사진도 찍을 수 있어요. 누구나 자유롭게 참여할 수 있고, 슬라임 색깔은 파랑, 하늘색, 하양으로 준비돼 있답니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide09.jpg", "type": "infographic"}, {"scene": 10, "visual": "체험 상세 · 대형 바닥풍선", "narration": "대형 바닥풍선은 선생님과 함께 슬라임 풍선을 아주 크게 부풀려 보는 협동 챌린지예요. 두 명이 한 조가 되고, 연습 한 번에 본 도전 한 번을 해요. 큰 슬라임을 사용하고요. 진행하실 땐 두 명당 선생님 한 분이 붙어 주세요. 성공률은 97퍼센트라 거의 다 성공하고, 평균 3분 정도 걸려요. 최대 세 명까지 함께할 수 있어요. 두 게임을 모두 성공하면 리워드를 드리는데, 한 게임은 추가 결제고요, 파츠는 한 컵 드려요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide10.jpg", "type": "infographic"}, {"scene": 11, "visual": "체험 상세 · 슬라임 던지기", "narration": "슬라임 던지기는 찐득볼을 던지는 게임이에요. 부모님은 뒤쪽에 들어가 계시고, 아이가 부모님이나 선생님을 향해 던지는 협동 게임이죠. 연습 한 번, 본 도전 한 번을 하고, 세 번 던져서 70점을 넘기면 성공이에요. 글로블스를 사용하고요. 한 명당 선생님 한 분이 함께해요. 성공률은 80퍼센트, 평균 1분 정도 걸려요. 한 번에 한 명이 참여하고요. 두 게임을 모두 성공하면 리워드를 드려요. 한 게임은 추가 결제, 파츠는 한 컵이에요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide11.jpg", "type": "infographic"}, {"scene": 12, "visual": "공간 구성 · 동선", "narration": "매장 공간 구성도 알아 둘게요. 죽전점은 50평 규모예요. 크게 만들기존, 체험존, 굿즈존으로 나뉘어요. 손님은 입구로 들어와서 카운터를 거친 다음, 만들기존과 굿즈존, 체험존으로 이동하게 돼요. 동선과 안전을 늘 신경 써 주세요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide12.jpg", "type": "infographic"}, {"scene": 13, "visual": "비상연락 · 안전 · 결제", "narration": "이 페이지엔 주차 안내와 자주 묻는 질문, 그리고 꼭 알아야 할 정보가 모여 있어요. 먼저 비상 연락망이에요. 이마트 쪽은 정 담당 정우민 매니저 010-8466-5541, 부 담당 윤지호 대리 010-9925-5833이고요. 슬라라 쪽은 정 담당 이학규 본부장 010-4065-2845, 부 담당 장진호 선임 010-8581-0381이에요. 슬라임은 KC 인증 기준에 맞춰 만든 안전한 제품이지만, 먹거나 눈이나 입에 넣지 않도록 꼭 안내해 주세요. 옷이나 신발에 묻을 수 있으니 편한 복장을 권해 드리고요. 혹시 묻었다면 미지근한 물에 식초를 섞어 슬라임을 녹인 뒤 세탁하시면 돼요. 세게 문지르면 번지니까 가볍게 떼어 낸 뒤 빠는 게 좋아요. 소재에 따라 얼룩이 남을 수 있어서 따로 보상은 어렵다는 점도 정중히 말씀드려요. 마지막으로 포스기 아이디는 870070, 비밀번호는 00000이에요. 결제하실 때는 ‘신세계 포인트 적립해 드릴까요?’ 하고 꼭 여쭤봐 주세요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide13.jpg", "type": "infographic"}, {"scene": 14, "visual": "직원 식당 위치", "narration": "여기는 직원 식당 위치예요. 식사 시간에 헤매지 않도록 미리 알아 두세요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide14.jpg", "type": "infographic"}, {"scene": 15, "visual": "출입구 위치", "narration": "이건 출입구 위치예요. 손님을 안내하실 때 참고하시면 좋아요.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide15.jpg", "type": "infographic"}, {"scene": 16, "visual": "쓰레기 처리장 위치", "narration": "쓰레기 처리장 위치예요. 하역장 쓰레기를 그날그날 버릴 때 이쪽을 이용하시면 됩니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide16.jpg", "type": "infographic"}, {"scene": 17, "visual": "메모", "narration": "마지막은 메모 페이지예요. 현장에서 새로 알게 된 점이나 기억할 내용을 자유롭게 적어 두세요. 오늘도 즐겁게, 슬라라!", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide17.jpg", "type": "infographic"}]'::jsonb,
   '[{"question": "손님이 들어오시면 가장 먼저 무엇을 하나요?", "options": ["가격부터 안내한다", "‘안녕하세요, 슬라라입니다!’ 하고 밝게 인사한다", "체험존으로 데려간다", "결제를 유도한다"], "correct": 1, "explanation": "모든 응대의 첫 스텝은 밝은 인사예요.", "type": "mc", "difficulty": "medium"}, {"question": "손님이 ‘여기는 뭐 하는 곳이에요?’ 하고 물으면 어떻게 안내하나요?", "options": ["‘슬라임 카페예요. 1만 8천 원에 키트를 다 드리고 옆 게임도 하나 체험하실 수 있어요’라고 안내", "가격표를 보라고 한다", "그냥 체험존을 가리킨다", "담당자를 부른다"], "correct": 0, "explanation": "기본 1만 8천 원 구성과 게임 한 종을 함께 안내합니다.", "type": "mc", "difficulty": "medium"}, {"question": "한 번 결제하면 체험을 얼마 동안 즐길 수 있나요?", "options": ["30분", "1시간", "1시간 30분", "2시간"], "correct": 1, "explanation": "이용 시간은 한 시간이에요.", "type": "mc", "difficulty": "medium"}, {"question": "권장 연령은 몇 살부터인가요?", "options": ["만 한 살", "만 세 살", "만 다섯 살", "만 일곱 살"], "correct": 1, "explanation": "권장 연령은 만 세 살부터예요.", "type": "mc", "difficulty": "medium"}, {"question": "여덟 살 이하 어린이는 어떻게 입장하나요?", "options": ["혼자 입장 가능", "보호자와 함께 입장", "입장 불가", "직원이 동행"], "correct": 1, "explanation": "여덟 살 이하는 보호자 동반이 필수예요.", "type": "mc", "difficulty": "medium"}, {"question": "손님이 게임을 하나 더 하고 싶어 하시면 추가 요금은 얼마인가요?", "options": ["1천 원", "2천 원", "3천 원", "무료"], "correct": 2, "explanation": "게임 한 종 추가는 3천 원이에요.", "type": "mc", "difficulty": "medium"}, {"question": "아이스크림을 추가로 사고 싶어 하시면 얼마라고 안내하나요?", "options": ["3천 원", "5천 원", "1만 2천 원", "1만 8천 원"], "correct": 2, "explanation": "아이스크림 추가는 1만 2천 원이에요.", "type": "mc", "difficulty": "medium"}, {"question": "파츠 한 통 추가 가격은?", "options": ["1천 원", "2천 원", "3천 원", "5천 원"], "correct": 2, "explanation": "파츠 한 통은 3천 원이에요.", "type": "mc", "difficulty": "medium"}, {"question": "토핑 추가 가격은?", "options": ["1천 원", "2천 원", "3천 원", "4천 원"], "correct": 1, "explanation": "토핑은 2천 원이에요.", "type": "mc", "difficulty": "medium"}, {"question": "손님이 오시면 스티커 뒷면에 무엇을 적어 드리나요?", "options": ["이름", "체험이 끝나는 시간", "좌석 번호", "전화번호"], "correct": 1, "explanation": "예를 들어 1시 방문이면 2시라고 적고 한 시간 이용을 안내해요.", "type": "mc", "difficulty": "medium"}, {"question": "대형 바닥풍선은 몇 명이 한 조가 되나요?", "options": ["한 명", "두 명", "세 명", "네 명"], "correct": 1, "explanation": "바닥풍선은 두 명이 한 조로, 선생님과 협동해요.", "type": "mc", "difficulty": "medium"}, {"question": "대형 바닥풍선의 성공률은 어느 정도인가요?", "options": ["80퍼센트", "90퍼센트", "95퍼센트", "97퍼센트"], "correct": 3, "explanation": "바닥풍선 성공률은 97퍼센트예요.", "type": "mc", "difficulty": "medium"}, {"question": "슬라임 던지기의 성공률은?", "options": ["70퍼센트", "80퍼센트", "90퍼센트", "97퍼센트"], "correct": 1, "explanation": "슬라임 던지기 성공률은 80퍼센트예요.", "type": "mc", "difficulty": "medium"}, {"question": "슬라임이 옷에 묻었을 때 어떻게 안내하나요?", "options": ["뜨거운 물로 세탁", "미지근한 물에 식초를 섞어 녹인 뒤 세탁", "표백제 사용", "바로 드라이클리닝"], "correct": 1, "explanation": "미지근한 물에 식초를 섞어 녹인 뒤 가볍게 떼어 내고 세탁해요.", "type": "mc", "difficulty": "medium"}, {"question": "슬라임 월에 없는 슬라임 색깔은?", "options": ["파랑", "하늘색", "하양", "빨강"], "correct": 3, "explanation": "슬라임 월 색깔은 파랑, 하늘색, 하양이에요.", "type": "mc", "difficulty": "medium"}, {"question": "결제하실 때 손님께 꼭 여쭤봐야 하는 것은?", "options": ["멤버십 가입", "신세계 포인트 적립", "영수증 필요 여부", "주차 등록"], "correct": 1, "explanation": "결제 시 신세계 포인트 적립 여부를 꼭 여쭤봐요.", "type": "mc", "difficulty": "medium"}, {"question": "문을 연 뒤 체험존·굿즈존 사진은 어떻게 하나요?", "options": ["본사 이메일로 전송", "단체 채팅방에 공유", "개인 보관", "따로 안 함"], "correct": 1, "explanation": "오픈 후 체험존·굿즈존 사진을 단체 채팅방에 공유해요.", "type": "mc", "difficulty": "medium"}, {"question": "우리가 가장 중요하게 여기는 가치 세 가지는?", "options": ["재미, 친절, 플러스원", "속도, 정확, 절약", "가격, 품질, 서비스", "청결, 안전, 질서"], "correct": 0, "explanation": "슬라라의 가치는 ‘재미, 친절, 플러스원’이에요.", "type": "mc", "difficulty": "medium"}]'::jsonb,
